import React, { useEffect, useRef } from 'react';
import { useChat } from '../context/ChatContext';
import { useAuth } from '../context/AuthContext';
import MessageInput from './MessageInput';
import './ChatWindow.css';

const ChatWindow = () => {
  const { selectedUser, messages, typing, markAsRead } = useChat();
  const { user } = useAuth();

  const chatMessages = selectedUser ? messages[selectedUser._id] || [] : [];
  const isTyping = selectedUser && typing[selectedUser._id];
  const messagesEndRef = useRef(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatMessages]);

  // Mark messages as read when viewing a conversation
  useEffect(() => {
    if (selectedUser) {
      markAsRead(selectedUser._id);
    }
  }, [selectedUser, chatMessages, markAsRead]);

  if (!selectedUser) {
    return (
      <div className="chat-window empty">
        <div className="empty-state">
          <h3>Select a user to start chatting</h3>
          <p>Choose someone from the online users list</p>
        </div>
      </div>
    );
  }

  return (
    <div className="chat-window">
      <div className="chat-window-header">
        <div className="chat-user-info">
          <div className="chat-user-avatar">
            {selectedUser.nickname.charAt(0).toUpperCase()}
          </div>
          <div>
            <h4>{selectedUser.nickname}</h4>
            <span className={`gender-badge ${selectedUser.gender?.toLowerCase()}`}>
              {selectedUser.gender}
            </span>
          </div>
        </div>
      </div>

      <div className="messages-container">
        {chatMessages.map((msg, index) => (
          <div
            key={index}
            className={`message ${msg.from === user._id ? 'sent' : 'received'}`}
          >
            <p>{msg.text}</p>
            <span className="message-time">
              {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
            </span>
          </div>
        ))}
        {isTyping && (
          <div className="typing-indicator">
            <span>{selectedUser.nickname} is typing...</span>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <MessageInput />
    </div>
  );
};

export default ChatWindow;
